// Join criteria + evidence into (bidder, criterion, evidence) triplets.
// One item per (bidder_id × criterion_id) pair — ready for the verdict loop.

const webhookData = $('Webhook Trigger').first().json;
const bidder_ids = webhookData.bidder_ids || [];
const tender_id = webhookData.tender_id;

const criteriaRaw = $('Fetch All Criteria').first().json;
const criteria = Array.isArray(criteriaRaw) ? criteriaRaw : (criteriaRaw.criteria || []);

const evidenceRaw = $('Fetch All Evidence').first().json;
const evidenceList = Array.isArray(evidenceRaw) ? evidenceRaw : (evidenceRaw.evidence || []);

// Build lookup: bidder_id + criterion_id -> evidence
const evidenceMap = {};
for (const e of evidenceList) {
  const key = `${e.bidder_id}__${e.criterion_id}`;
  evidenceMap[key] = e;
}

const tender_submission_date = webhookData.submission_date || null;

const pairs = [];
for (const bidder_id of bidder_ids) {
  for (const criterion of criteria) {
    const key = `${bidder_id}__${criterion.id}`;
    const evidence = evidenceMap[key] || null;

    pairs.push({
      tender_id,
      bidder_id,
      tender_submission_date,
      criterion_id: criterion.id,
      criterion_name: criterion.name,
      criterion_type: criterion.type,          // financial|technical|compliance|certification
      threshold_value: criterion.threshold_value ?? null,
      threshold_unit: criterion.threshold_unit ?? null,
      mandatory: criterion.mandatory,
      source_section: criterion.source_section,
      // Evidence fields — null if not found
      evidence_id: evidence?.id ?? null,
      extracted_value: evidence?.value ?? null,
      extracted_unit: evidence?.unit ?? null,
      extracted_confidence: evidence?.confidence ?? 0.0,
      quoted_text: evidence?.quoted_text ?? null,
      source_page: evidence?.source_page ?? null,
      not_found_reason: evidence?.not_found_reason ?? null,
      evidence_missing: evidence === null || evidence?.value === null
    });
  }
}

return pairs.map(p => ({ json: p }));

// ════════════════════════════════════════════════
// RULE LAYER — runs before any LLM call.
// Handles: missing evidence, numeric, certification
// date expiry, compliance boolean.
// Returns verdict or 'needs_llm' for semantic cases.
// ════════════════════════════════════════════════

const p = $input.first().json;

// Helper: normalise Indian number formats to float
// Handles: "50,00,000" / "₹1.4 crore" / "1.4 crores" / "140 lakhs"
function toFloat(val) {
  if (val === null || val === undefined) return null;
  if (typeof val === 'number') return val;
  let s = String(val).toLowerCase();
  // Remove currency symbols and spaces
  s = s.replace(/[₹$,\s]/g, '');
  // Crore conversion
  if (s.includes('crore')) {
    const n = parseFloat(s.replace(/crores?/, ''));
    return isNaN(n) ? null : n * 10000000;
  }
  // Lakh conversion
  if (s.includes('lakh')) {
    const n = parseFloat(s.replace(/lakhs?/, ''));
    return isNaN(n) ? null : n * 100000;
  }
  const n = parseFloat(s);
  return isNaN(n) ? null : n;
}

// Helper: parse date string to comparable value
function parseDate(val) {
  if (!val) return null;
  const d = new Date(val);
  return isNaN(d.getTime()) ? null : d;
}

function makeVerdict(verdict, reason, confidence, method) {
  return {
    ...p,
    verdict,
    reason,
    verdict_confidence: confidence,
    verdict_method: method,
    needs_llm: false,
    decided_at: new Date().toISOString()
  };
}

// ── Rule 1: Evidence completely missing ──────────
if (p.evidence_missing) {
  return [{ json: makeVerdict(
    'MANUAL_REVIEW',
    p.not_found_reason || 'No evidence found in bidder submitted documents',
    1.0,
    'rule_missing'
  )}];
}

// ── Rule 2: Low extraction confidence ───────────
// Skip rules entirely if confidence is too low
if (p.extracted_confidence < 0.60) {
  return [{ json: {
    ...p,
    verdict: null,
    needs_llm: true,
    llm_reason: `Extraction confidence too low (${p.extracted_confidence}) — needs LLM review`,
    decided_at: new Date().toISOString()
  }}];
}

// ── Rule 3: Financial / numeric threshold ────────
if (p.criterion_type === 'financial') {
  const extracted = toFloat(p.extracted_value);
  const threshold = toFloat(p.threshold_value);

  if (extracted === null) {
    return [{ json: makeVerdict(
      'MANUAL_REVIEW',
      `Could not parse extracted value "${p.extracted_value}" as a number`,
      0.9,
      'rule_parse_failed'
    )}];
  }

  if (threshold === null) {
    // No threshold to compare — needs LLM
    return [{ json: { ...p, verdict: null, needs_llm: true, llm_reason: 'Financial criterion has no numeric threshold — semantic review needed', decided_at: new Date().toISOString() } }];
  }

  // High-confidence rule decision
  if (p.extracted_confidence >= 0.80) {
    const pass = extracted >= threshold;
    return [{ json: makeVerdict(
      pass ? 'ELIGIBLE' : 'INELIGIBLE',
      pass
        ? `Extracted value ${extracted} meets threshold ${threshold} ${p.threshold_unit || ''}`
        : `Extracted value ${extracted} is below threshold ${threshold} ${p.threshold_unit || ''}`,
      0.95,
      'rule_numeric'
    )}];
  }

  // Borderline confidence — send to LLM
  return [{ json: { ...p, needs_llm: true, llm_reason: `Numeric comparison clear but extraction confidence ${p.extracted_confidence} is borderline`, decided_at: new Date().toISOString() } }];
}

// ── Rule 4: Certification expiry date ────────────
if (p.criterion_type === 'certification') {
  // extracted_value should be the expiry date of the certificate
  const expiryDate = parseDate(p.extracted_value);
  const submissionDate = p.tender_submission_date ? parseDate(p.tender_submission_date) : new Date();

  if (expiryDate === null) {
    return [{ json: { ...p, verdict: null, needs_llm: true, llm_reason: `Could not parse certificate expiry date from "${p.extracted_value}"`, decided_at: new Date().toISOString() } }];
  }

  const isValid = expiryDate > submissionDate;
  return [{ json: makeVerdict(
    isValid ? 'ELIGIBLE' : 'INELIGIBLE',
    isValid
      ? `Certificate valid until ${p.extracted_value} — beyond submission date`
      : `Certificate EXPIRED on ${p.extracted_value} — before submission date`,
    0.99,
    'rule_date'
  )}];
}

// ── Rule 5: Compliance (GST / EPFO / ESIC) ───────
if (p.criterion_type === 'compliance') {
  const val = String(p.extracted_value || '').toLowerCase().trim();
  const POSITIVE = ['yes', 'true', '1', 'active', 'registered', 'valid', 'present'];
  const NEGATIVE = ['no', 'false', '0', 'inactive', 'cancelled', 'expired', 'absent'];

  if (POSITIVE.some(v => val.includes(v))) {
    return [{ json: makeVerdict('ELIGIBLE', `Registration/compliance confirmed: "${p.extracted_value}"`, 0.95, 'rule_boolean') }];
  }
  if (NEGATIVE.some(v => val.includes(v))) {
    return [{ json: makeVerdict('INELIGIBLE', `Registration/compliance failed: "${p.extracted_value}"`, 0.95, 'rule_boolean') }];
  }
  // Value present but not clearly positive/negative — LLM needed
  return [{ json: { ...p, verdict: null, needs_llm: true, llm_reason: `Compliance value "${p.extracted_value}" is ambiguous — not a clear yes/no`, decided_at: new Date().toISOString() } }];
}

// ── Rule 6: Technical (similar work, scope) ───────
// Always goes to LLM — semantic judgment required
if (p.criterion_type === 'technical') {
  return [{ json: { ...p, verdict: null, needs_llm: true, llm_reason: 'Technical criterion requires semantic similarity judgment', decided_at: new Date().toISOString() } }];
}

// ── Fallback: unknown type → LLM ─────────────────
return [{ json: { ...p, verdict: null, needs_llm: true, llm_reason: `Unknown criterion type "${p.criterion_type}"`, decided_at: new Date().toISOString() } }];

